INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '73d6c86d-039d-46ad-b023-5e1764d318a7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Securing Your App with Snyk: XSS Variants and CSP Headers$escape$,
  $escape$Snyk's Vulnerability Database helps you identify Cross-Site Scripting (XSS) vulnerabilities in your dependencies. When analyzing an application, Snyk classifies XSS vulnerabilities into three categories: Reflected, Stored, and DOM-based. Reflected XSS occurs when user input is directly reflected in the application's response. Stored XSS happens when user input is stored in a database and later executed by the application. DOM-based XSS occurs when user input is executed in the application's client-side JavaScript. To mitigate Stored and Reflected XSS, Snyk recommends using Content-Security-Policy (CSP) headers, which specify allowed sources for certain types of content. You can configure CSP headers in Snyk's Policy Manager. To encode user input and prevent XSS, use Snyk's `encode` function, which can be accessed through the `snyk.security.html.encode` API.$escape$,
  NULL,
  NULL,
