INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bda2367e-7b0e-4750-8db1-6e12413d35e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snyk: Detecting Default Credentials and Exposed Debug Endpoints$escape$,
  $escape$Snyk's Vulnerability DB contains many vulnerabilities caused by default credentials and exposed debug endpoints. To detect these issues, use the `snyk test` command with the `--default-credentials` and `--exposed-endpoints` flags. For example:
snyk test --default-credentials --exposed-endpoints 
  --file=package.json
  --project=example-project

This will scan your project for vulnerabilities and report any findings.$escape$,
  NULL,
  NULL,
