INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '42e49eee-2d96-4249-8841-6303bb8239ed',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snyk — Automating DAST with Burp Suite and ZAP$escape$,
  $escape$To integrate dynamic application security testing (DAST) with Snyk, utilize Snyk's custom scripts feature. Snyk supports Burp Suite and ZAP as DAST tools. Create a custom script with the `snyk dast` command, specifying the tool and target application. For example, to run a ZAP scan, use `snyk dast zap --target https://example.com`. You can also configure the script to run scans on a schedule using Snyk's CI/CD integrations.$escape$,
  $escape$snyk dast zap --target https://example.com
snyk dast zap --target https://example.com --schedule '* * * * * *'$escape$,
  $escape$bash$escape$,
