INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f5f08320-92ca-4036-97b9-6bd5e4c49655',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snyk: Never Commit Secrets with TruffleHog and Gitleaks$escape$,
  $escape$Snyk's vulnerability scanner can detect secrets stored in your code repository. Use TruffleHog and Gitleaks to scan your repository for secrets and rotate them with Snyk's Secret Manager. Integrate TruffleHog into your Snyk workflow by configuring a custom Snyk CLI command. Use Snyk's Secret Manager to rotate sensitive data, like API keys, and store them securely.$escape$,
