INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd21c59ff-621b-4b55-a896-933d47ba7313',
  '00000000-0000-0000-0000-000000000001',
  $escape$snyk: Threat Modeling with STRIDE and Trust Boundaries$escape$,
  $escape$Snyk's Vulnerability Database (VDB) provides a comprehensive threat modeling framework based on the STRIDE attack model. To identify trust boundaries, use the `snyk vulnerability list` command with the `--trust-boundary` flag. This flag highlights vulnerabilities that compromise sensitive data or system trust. For example, to identify vulnerabilities in the `my-app` package with trust boundary issues, run `snyk vulnerability list --trust-boundary my-app`. This will output a list of vulnerabilities with trust boundary concerns. To visualize your attack surface, use Snyk's Dependency Graph feature. This visual representation helps you identify vulnerable dependencies and their impact on your application.$escape$,
  $escape$snyk vulnerability list --trust-boundary my-app$escape$,
  $escape$bash$escape$,
